    if (IsAnd && Pred1 == ICmpInst::ICMP_NE && Pred2 == ICmpInst::ICMP_NE &&
        match(ICmp1->getOperand(0), m_And(m_Specific(V2), m_APInt(Offset1))) &&
        Offset1->isNonNegative() && Offset1->isPowerOf2()) {
      // Input is of the form: (x & -mask) != val1 and x != val2
      APInt Mask = -*Offset1; // positive mask
      APInt Val1 = *C1;
      APInt Val2 = *C2;

      // The mask aligns the value to a stride of Mask. We can fold the two
      // predicates if val1 is aligned to the mask and val2 differs only in the
      // lower bits.
      if (Val1.countTrailingZeros() >= Mask.countTrailingZeros()) {
        APInt LowerBits = APInt::getLowBitsSet(Mask.getBitWidth(),
                                               Mask.countTrailingZeros());
        APInt StripedVal2 = Val2 & ~LowerBits;
        if ((Val1 & ~LowerBits) == StripedVal2) {
